+    use libm::fabsf;
+
+    #[test]
+    fn test_const_new() {
+        let ds = DreamStageDetector::new();
+        assert_eq!(ds.frame_count(), 0);
+        assert_eq!(ds.stage(), SleepStage::Awake);
+        assert!(fabsf(ds.efficiency()) < 1e-6);
+    }
+
