+        let vars = [1.0f32; 32]; // high variance
+        let amps = [1.0f32; 32];
+        for _ in 0..100 {
+            let events = rd.process_frame(&phases, &vars, &amps, 1); // present
+            assert!(events.is_empty());
+        }
