+        assert_eq!(RainIntensity::Moderate as u8, 2);
+        assert_eq!(RainIntensity::Heavy as u8, 3);
+    }
+
+    #[test]
+    fn test_insufficient_subcarriers() {
+        let mut rd = RainDetector::new();
+        let small = [1.0f32; 4];
+        let events = rd.process_frame(&small, &small, &small, 0);
