+    }
+
+    #[test]
+    fn test_reset() {
+        let mut rd = RainDetector::new();
+        let phases = [0.5f32; 32];
+        let vars = [0.001f32; 32];
+        let amps = [1.0f32; 32];
+        for _ in 0..50 {
+            rd.process_frame(&phases, &vars, &amps, 0);
+        }
+        assert!(rd.frame_count() > 0);
+        rd.reset();
+        assert_eq!(rd.frame_count(), 0);
+        assert!(!rd.is_raining());
+    }
