+        // --- Step 5: Periodic vibration spectrum report ---
+        if self.frame_count % SPECTRUM_REPORT_INTERVAL == 0
+            && self.hist_len >= MAX_LAGS + 1
+            && n_events < 4
+        {
+            unsafe { EVENTS[n_events] = (EVENT_VIBRATION_SPECTRUM, rms); }
+            n_events += 1;
+        }
